// Filter calendar events: 7 days back to 180 days forward from today
const KALEVENT = (() => {
  const now = new Date();
  const from = new Date(now); from.setDate(from.getDate() - 7);
  const to   = new Date(now); to.setDate(to.getDate() + 180);
  return KALEVENT_ALL.filter(e => {
    const d = new Date(e.datum + "T12:00:00");
    return d >= from && d <= to;
  });
})();

// ─── SUPABASE CONFIG ──────────────────────────────────────────────────
const SUPA_URL = import.meta.env.VITE_SUPABASE_URL || "";
const SUPA_KEY = import.meta.env.VITE_SUPABASE_KEY || "";
const SUPA_OK  = !!(SUPA_URL && SUPA_KEY);

async function supaGet(table, key) {
  if (!SUPA_OK) return null;
  try {
    const r = await fetch(`${SUPA_URL}/rest/v1/${table}?key=eq.${encodeURIComponent(key)}&select=value`, {
      headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
    });
    const rows = await r.json();
    return rows?.[0]?.value ?? null;
  } catch { return null; }
}

async function supaSet(table, key, value) {
  if (!SUPA_OK) return false;
  try {
    const r = await fetch(`${SUPA_URL}/rest/v1/${table}`, {
      method: "POST",
      headers: {
        apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}`,
        "Content-Type": "application/json",
        Prefer: "resolution=merge-duplicates",
      },
      body: JSON.stringify({ key, value }),
    });
    return r.ok;
  } catch { return false; }
}

