// ═══════════════════════════════════════════════════════════════════════
// PLANERINGS VY (startsidan)
// ═══════════════════════════════════════════════════════════════════════
const PlaneringsVy = ({blocks, appState, setAppState, setBlocks, onStartCoach, onVisaAvslutad, onRedigera, onOvningsbank, onVarderingar, onArbetssatt, syncBadge, trupp, onRefreshTrupp, mvBlocks, setMvBlocks}) => {
  const [openBlock, setOpenBlock] = useState(blocks[0]?.id||1);
  const [visaAvslutade, setVisaAvslutade] = useState(false);
  const [showGenModal, setShowGenModal] = useState(false);
  const [genSkeden, setGenSkeden] = useState([]);
  const [lagTyp, setLagTyp] = useState("lag"); // "lag" | "mv"
  const [dragIdx, setDragIdx] = useState(null);
  const [dragOverIdx, setDragOverIdx] = useState(null);

  const getTranState = (bId,tNr) => appState[tranKey(bId,tNr)] || {};
  const setEvent = (bId,tNr,eid) => { const k=tranKey(bId,tNr); setAppState(p=>({...p,[k]:{...p[k],event:eid}})); };
  const isAvslutad = (bId,tNr) => !!getTranState(bId,tNr).avslutad;

  const aktiveraBlocks = lagTyp==="mv" ? mvBlocks : blocks;
  const totalt = aktiveraBlocks.reduce((s,b)=>s+b.trän.length,0);
  const avslutade = aktiveraBlocks.reduce((s,b)=>s+b.trän.filter(t=>isAvslutad(b.id,t.nr)).length,0);
  const koppladeEvent = aktiveraBlocks.reduce((s,b)=>s+b.trän.filter(t=>getTranState(b.id,t.nr).event).length,0);

  // Check if last block is complete
  const sistaBlock = aktiveraBlocks[aktiveraBlocks.length-1];
  const sistaBlockKlar = sistaBlock && sistaBlock.trän.every(t=>isAvslutad(sistaBlock.id,t.nr));

  const handleGenBlock = () => {
    if (lagTyp === "mv") {
      const nb = genMVBlock(mvBlocks);
      const newMv = [...mvBlocks, nb];
      setMvBlocks(newMv);
      setOpenBlock(nb.id);
    } else {
      const nb = genBlock(blocks, genSkeden.length > 0 ? genSkeden : null);
      const newBlocks = [...blocks, nb];
      setBlocks(newBlocks);
      setOpenBlock(nb.id);
    }
    setShowGenModal(false);
    setGenSkeden([]);
  };
  const toggleGenSkede = (s) => setGenSkeden(p => p.includes(s) ? p.filter(x=>x!==s) : [...p,s]);

  return (
    <div className="min-h-screen bg-slate-100">
      {/* Header */}
      <header className="sticky top-0 z-30 bg-blue-950 border-b-4 border-yellow-400/50 shadow-xl">
        <div className="max-w-4xl mx-auto px-4 py-3 flex items-center justify-between gap-3">
          <div className="flex items-center gap-2.5">
            <img src={LOGO} alt="RIK" className="h-9 w-9 object-contain"/>
            <div>
              <div className="text-white font-black text-sm leading-tight">Rynninge IK · P14–16</div>
              <div className="text-yellow-400 text-[10px] font-semibold tracking-wide">ETT SÄTT ATT UMGÅS</div>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={onOvningsbank} className="flex items-center gap-1.5 text-xs font-bold bg-white/10 hover:bg-white/20 text-white border border-white/20 px-3 py-2 rounded-xl transition-colors">
              <BookOpen className="h-3.5 w-3.5"/>Övningar
            </button>
            <button onClick={onVarderingar} className="flex items-center gap-1.5 text-xs font-bold bg-white/10 hover:bg-white/20 text-white border border-white/20 px-3 py-2 rounded-xl transition-colors">
              <Star className="h-3.5 w-3.5"/>Värderingar
            </button>
            <button onClick={onArbetssatt} className="flex items-center gap-1.5 text-xs font-bold bg-white/10 hover:bg-white/20 text-white border border-white/20 px-3 py-2 rounded-xl transition-colors">
              <span className="text-sm">🧩</span>Arbetssätt
            </button>
            <button onClick={()=>setVisaAvslutade(v=>!v)} className={`flex items-center gap-1.5 text-xs font-bold px-3 py-2 rounded-xl border transition-colors ${visaAvslutade?"bg-yellow-400 text-blue-950 border-yellow-400":"bg-white/10 text-white border-white/20 hover:bg-white/20"}`}>
              <Eye className="h-3.5 w-3.5"/>{visaAvslutade?"Dölj avslutade":"Visa avslutade"}
            </button>
            <button onClick={onRefreshTrupp} className="flex items-center gap-1.5 text-xs font-bold bg-white/10 hover:bg-white/20 text-white border border-white/20 px-2.5 py-2 rounded-xl transition-colors" title="Uppdatera spelarlistan från laget.se">
              <RefreshCw className="h-3.5 w-3.5"/>
            </button>
            {syncBadge}
          </div>
        </div>
      </header>

      <div className="max-w-4xl mx-auto px-4 py-5 space-y-3">
        {/* Progress */}
        <div className="bg-white rounded-2xl p-4 shadow-sm ring-1 ring-slate-200">
          <div className="flex items-center justify-between mb-2">
            <div className="text-sm font-black text-slate-700">Säsongsframsteg</div>
            <div className="text-sm font-bold text-slate-500">{avslutade}/{totalt} träningar</div>
          </div>
          <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
            <div className="h-full rounded-full bg-gradient-to-r from-blue-700 to-yellow-400 transition-all duration-500" style={{width:`${totalt>0?(avslutade/totalt)*100:0}%`}}/>
          </div>
          <div className="flex justify-between mt-2 text-[10px] text-slate-400 font-semibold">
            <span>{avslutade} avslutade</span>
            <span>{koppladeEvent} kopplade till kalender</span>
            <span>{totalt-avslutade} kvar</span>
          </div>
        </div>

        {/* Lagtyp toggle */}
        <div className="bg-white rounded-2xl p-1.5 shadow-sm ring-1 ring-slate-200 flex gap-1.5">
          <button onClick={()=>setLagTyp("lag")}
            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-black transition-all ${lagTyp==="lag"?"bg-blue-950 text-white shadow":"text-slate-500 hover:bg-slate-50"}`}>
            ⚽ Lagträning
          </button>
          <button onClick={()=>setLagTyp("mv")}
            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-black transition-all ${lagTyp==="mv"?"bg-violet-700 text-white shadow":"text-slate-500 hover:bg-slate-50"}`}>
            🧤 Målvaktsträning
          </button>
        </div>

        {/* Generera block-prompt */}
        {sistaBlockKlar&&(
          <div className="bg-green-50 border border-green-300 rounded-2xl p-4 flex items-center justify-between gap-3">
            <div>
              <div className="font-black text-green-800 text-sm">✅ {sistaBlock.titel} är klart!</div>
              <div className="text-xs text-green-700 mt-0.5">Dags att generera nästa träningsblock baserat på dina schemalagda träningstillfällen.</div>
            </div>
            <button onClick={()=>setShowGenModal(true)} className="flex items-center gap-1.5 bg-green-700 hover:bg-green-600 text-white px-4 py-2.5 rounded-xl text-sm font-black flex-shrink-0">
              <PlusCircle className="h-4 w-4"/>Nytt block
            </button>
          </div>
        )}

        {/* BLOCK */}
        {aktiveraBlocks.map((block, bi)=>{
          const isOpen=openBlock===block.id;
          const bc = (block.typ==="MV") ? MV_BLOCKFARG : BLOCKFARG[bi%BLOCKFARG.length];
          const blokAvslutade=block.trän.filter(t=>isAvslutad(block.id,t.nr)).length;
          const synliga=block.trän.filter(t=>visaAvslutade||!isAvslutad(block.id,t.nr));
          const period=blockPeriod(block,appState);

          return(
            <div key={block.id} className={`rounded-2xl shadow-sm overflow-hidden ${dragOverIdx===bi?"ring-2 ring-yellow-400":""}`}>
              {/* Single full-width colored header row */}
              <div className={`${bc} flex items-stretch`}
                onDragOver={e=>{e.preventDefault();setDragOverIdx(bi);}}
                onDrop={()=>{
                  if(dragIdx===null||dragIdx===bi) return;
                  const lst=[...aktiveraBlocks];
                  const [moved]=lst.splice(dragIdx,1);
                  lst.splice(bi,0,moved);
                  if(lagTyp==="mv") setMvBlocks(lst); else setBlocks(lst);
                  setDragIdx(null); setDragOverIdx(null);
                }}
                onDragEnd={()=>{setDragIdx(null);setDragOverIdx(null);}}>
                {/* Drag grip */}
                <div draggable onDragStart={()=>setDragIdx(bi)}
                  className="flex items-center px-2.5 cursor-grab active:cursor-grabbing select-none opacity-50 hover:opacity-100 transition-opacity flex-shrink-0"
                  title="Dra för att byta ordning">
                  <span className="text-white text-base leading-none">⠿</span>
                </div>
                {/* Title + meta — clickable */}
                <button onClick={()=>setOpenBlock(isOpen?0:block.id)}
                  className="flex-1 text-white px-3 py-3 flex items-center gap-2 flex-wrap text-left hover:opacity-90 transition-opacity min-w-0">
                  <span className="font-black text-base leading-tight">{block.titel}</span>
                  <span className="text-xs bg-white/20 px-2 py-0.5 rounded font-semibold whitespace-nowrap">{period}</span>
                  <span className="text-xs bg-white/20 px-2 py-0.5 rounded font-semibold whitespace-nowrap">{block.vardeord}</span>
                  <span className="text-xs bg-white/20 px-2 py-0.5 rounded whitespace-nowrap">{blokAvslutade}/{block.trän.length} klara</span>
                </button>
                {/* Actions */}
                <div className="flex items-center gap-1 px-2 flex-shrink-0">
                  {aktiveraBlocks.length > 1 && (
                    <button onClick={e=>{e.stopPropagation();if(window.confirm(`Ta bort "${block.titel}"?\nNärvaro och betyg för detta block raderas.`)){if(lagTyp==="mv"){setMvBlocks(prev=>prev.filter(b=>b.id!==block.id));}else{setBlocks(prev=>prev.filter(b=>b.id!==block.id));}}}}
                      className="p-1.5 rounded-lg hover:bg-red-500/40 transition-colors text-white/70 hover:text-white" title="Ta bort block">
                      <X className="h-4 w-4"/>
                    </button>
                  )}
                  <button onClick={()=>setOpenBlock(isOpen?0:block.id)} className="p-1.5 text-white/80 hover:text-white transition-colors">
                    {isOpen?<ChevronUp className="h-5 w-5"/>:<ChevronDown className="h-5 w-5"/>}
                  </button>
                </div>
              </div>

              {isOpen&&(
                <div className="bg-white p-3 space-y-2 ring-1 ring-slate-200 rounded-b-2xl">
                  {synliga.length===0&&(
                    <div className="text-center text-slate-400 py-6 text-sm">Alla träningar avslutade. <button onClick={()=>setVisaAvslutade(true)} className="text-blue-600 font-bold underline">Visa avslutade</button></div>
                  )}
                  {synliga.map(tran=>{
                    const ts=getTranState(block.id,tran.nr);
                    const avslutad=!!ts.avslutad;
                    const ev=KALEVENT.find(e=>e.id===ts.event);
                    const blaAntal=TRUPP.filter(s=>ts.narvaro?.[s.id]?.status==="bla").length;
                    const vitAntal=TRUPP.filter(s=>ts.narvaro?.[s.id]?.status==="vit").length;
                    const harNarv=blaAntal+vitAntal>0;

                    return(
                      <div key={tran.nr} className={`border rounded-xl overflow-hidden transition-all ${avslutad?"border-emerald-200 bg-emerald-50 opacity-80":"border-slate-200 bg-white hover:border-blue-300"}`}>
                        <div className="flex items-start justify-between gap-3 p-3 flex-wrap">
                          <div className="flex items-start gap-3 min-w-0 flex-1">
                            <div className={`${DAGFARG[tran.dag]||"bg-slate-500"} text-white text-[10px] font-black px-2 py-1 rounded-lg flex-shrink-0 text-center leading-tight`}>
                              <div>{tran.dag.slice(0,3).toUpperCase()}</div><div>V{tran.vec}</div>
                            </div>
                            <div className="min-w-0 flex-1">
                              <div className="flex flex-wrap items-center gap-1.5 mb-1">
                                {tran.skeden.map(s=><SkedeBadge key={s} id={s}/>)}
                                {avslutad&&<span className="text-[10px] bg-emerald-100 text-emerald-700 border border-emerald-300 px-1.5 py-0.5 rounded font-bold">✓ Genomförd</span>}
                              </div>
                              <div className="text-sm font-bold text-slate-900 leading-snug">{tran.syfte.slice(0,80)}{tran.syfte.length>80?"…":""}</div>
                              <div className="text-xs text-slate-500 mt-0.5">{tran.delar.reduce((s,d)=>s+d.tid,0)} min · {tran.delar.length} delar</div>
                              <div className="flex flex-wrap gap-2 mt-1.5">
                                {ev&&<span className="text-[10px] bg-blue-50 text-blue-700 border border-blue-200 px-2 py-0.5 rounded-full font-semibold flex items-center gap-1"><Calendar className="h-3 w-3"/>{ev.label}</span>}
                                {harNarv&&<span className="text-[10px] text-slate-500 flex items-center gap-1">{blaAntal>0&&<span className="text-blue-600 font-bold">🔵{blaAntal}</span>}{vitAntal>0&&<span className="text-slate-500 font-bold ml-1">⚪{vitAntal}</span>}</span>}
                              </div>
                              {!avslutad&&(
                                <div className="mt-2 flex items-center gap-2 flex-wrap">
                                  <Calendar className="h-3.5 w-3.5 text-slate-400 flex-shrink-0"/>
                                  <select value={ts.event||""} onChange={e=>setEvent(block.id,tran.nr,e.target.value)}
                                    className="text-xs border border-slate-200 rounded-lg px-2 py-1 bg-white text-slate-700 focus:outline-none focus:ring-1 focus:ring-blue-400">
                                    <option value="">Koppla till laget.se-tillfälle…</option>
                                    {KALEVENT.map(e=><option key={e.id} value={e.id}>{e.label} ({e.dag})</option>)}
                                  </select>
                                </div>
                              )}
                            </div>
                          </div>
                          <div className="flex gap-1.5 flex-shrink-0 flex-wrap">
                            {!avslutad&&(
                              <button onClick={()=>onRedigera(block,tran)} className="flex items-center gap-1 bg-slate-100 hover:bg-slate-200 text-slate-700 border border-slate-300 px-2.5 py-1.5 rounded-xl text-xs font-bold transition-colors">
                                <Edit3 className="h-3.5 w-3.5"/>Redigera
                              </button>
                            )}
                            {avslutad?(
                              <button onClick={()=>onVisaAvslutad(block,tran)} className="flex items-center gap-1.5 bg-emerald-100 hover:bg-emerald-200 text-emerald-800 border border-emerald-300 px-3 py-2 rounded-xl text-xs font-bold transition-colors">
                                <Eye className="h-3.5 w-3.5"/>Visa
                              </button>
                            ):(
                              <button onClick={()=>onStartCoach(block,tran)} className="flex items-center gap-1.5 bg-blue-950 hover:bg-blue-800 text-white px-3 py-2 rounded-xl text-xs font-black transition-colors shadow-sm">
                                <Play className="h-3.5 w-3.5"/>Starta
                              </button>
                            )}
                          </div>
                        </div>
                        <div className="px-3 pb-2 flex flex-wrap gap-1">
                          {tran.principer.slice(0,4).map(p=><span key={p} className="text-[10px] bg-slate-100 text-slate-600 border border-slate-200 px-1.5 py-0.5 rounded font-medium">{p}</span>)}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}

        {/* Manuell generera block-knapp */}
        <button onClick={()=>setShowGenModal(true)} className="w-full flex items-center justify-center gap-2 border-2 border-dashed border-slate-300 text-slate-500 hover:border-blue-400 hover:text-blue-600 rounded-2xl py-4 text-sm font-bold transition-colors">
          <PlusCircle className="h-5 w-5"/>Generera nytt träningsblock
        </button>
      </div>

      {/* Generera block modal */}
      {showGenModal&&(
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4">
          <div className="bg-white rounded-2xl p-6 max-w-md w-full shadow-2xl">
            <div className="text-xl font-black text-slate-900 mb-1">Generera Block {blocks.length+1}</div>
            <p className="text-sm text-slate-500 mb-4">Välj vilket skeende blocket ska fokusera på. Varje träning får en förberedelseövning, färdighetsövning och spelövning.</p>
            <div className="text-xs font-black uppercase tracking-wider text-slate-500 mb-2">Fokus – välj ett eller flera skeenden</div>
            <div className="grid grid-cols-2 gap-2 mb-4">
              {[
                ["ANF","⚽","Anfallsspel","Speluppbyggnad, djupled, avslut"],
                ["FORS","🛡️","Försvarsspel","Press, täckning, förhindra avslut"],
                ["OMANF","⚡","Omst. → Anfall","Kontring, snabbt framåt"],
                ["OMFOR","🔄","Omst. → Försvar","Återerövring, kollektivt försvar"],
                ["MV","🧤","Målvaktsträning","Djupledsspel, inlägg, skott"],
                ["FYS","🏋️","Fysisk träning","Styrka, rörlighet, löpteknik"],
              ].map(([s,icon,label,sub])=>{
                const on=genSkeden.includes(s);
                return(
                  <button key={s} onClick={()=>toggleGenSkede(s)}
                    className={`flex items-start gap-2 p-3 rounded-xl border text-left transition-all ${on?"border-blue-700 bg-blue-50 ring-1 ring-blue-400":"border-slate-200 bg-slate-50 hover:border-blue-300"}`}>
                    <span className="text-xl flex-shrink-0">{icon}</span>
                    <div>
                      <div className={`text-xs font-black ${on?"text-blue-900":"text-slate-700"}`}>{label}</div>
                      <div className={`text-[10px] ${on?"text-blue-600":"text-slate-400"}`}>{sub}</div>
                    </div>
                    {on&&<span className="ml-auto text-blue-700">✓</span>}
                  </button>
                );
              })}
            </div>
            {genSkeden.length===0&&(
              <div className="text-xs text-amber-600 bg-amber-50 border border-amber-200 rounded-xl p-2.5 mb-4">
                Inget skeende valt — blocket genereras automatiskt baserat på SvFF:s progression.
              </div>
            )}
            {genSkeden.length>0&&(
              <div className="text-xs text-blue-700 bg-blue-50 border border-blue-200 rounded-xl p-2.5 mb-4">
                Block {blocks.length+1} fokuserar på: <strong>{genSkeden.join(" + ")}</strong>. Alla 6 träningar byggs med detta fokus, med 1–2 REP-övningar från föregående block.
              </div>
            )}
            <div className="flex gap-3">
              <button onClick={()=>{setShowGenModal(false);setGenSkeden([]);}} className="flex-1 border border-slate-200 px-4 py-2.5 rounded-xl text-sm font-bold text-slate-700 hover:bg-slate-50">Avbryt</button>
              <button onClick={handleGenBlock} className="flex-1 bg-blue-950 hover:bg-blue-900 text-white px-4 py-2.5 rounded-xl text-sm font-black flex items-center justify-center gap-2">
                <PlusCircle className="h-4 w-4"/>Generera block {blocks.length+1}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// ═══════════════════════════════════════════════════════════════════════
// ROOT APP – med Supabase-synk
// ═══════════════════════════════════════════════════════════════════════
export default function App() {
  const [appState, setAppState] = useState(() => lsGet("_state", {}));
  const [blocks,   setBlocks]   = useState(() => lsGet("_blocks", null) || GRUNDBLOCK);
  const [mvBlocks, setMvBlocks] = useState(() => lsGet("_mvblocks", null) || []);
  const [favs,     setFavs]     = useState(() => loadF());
  const [view,     setView]     = useState("plan");
  const [trupp,    setTrupp]    = useState(TRUPP);
  const [syncStatus, setSyncStatus] = useState(SUPA_OK ? "idle" : "offline");
  const [activeBlock, setActiveBlock] = useState(null);
  const [activeTran,  setActiveTran]  = useState(null);
  const syncTimer = useRef(null);

  // ── Ladda från Supabase vid start ──────────────────────────────────
  useEffect(() => {
    if (!SUPA_OK) return;
    setSyncStatus("loading");
    Promise.all([
      supaGet("rik_kv", "state"),
      supaGet("rik_kv", "blocks"),
      supaGet("rik_kv", "mvblocks"),
    ]).then(([remoteState, remoteBlocks, remoteMvBlocks]) => {
      if (remoteState)  { setAppState(remoteState);     lsSet("_state", remoteState); }
      if (remoteBlocks) { setBlocks(remoteBlocks);       lsSet("_blocks", remoteBlocks); }
      if (remoteMvBlocks){ setMvBlocks(remoteMvBlocks); lsSet("_mvblocks", remoteMvBlocks); }
      setSyncStatus("synced");
    }).catch(() => setSyncStatus("offline"));
  }, []);

  // ── Synka till Supabase med debounce (500ms) ─────────────────────
  const syncAll = useCallback((newState, newBlocks, newMvBlocks) => {
    lsSet("_state",    newState);
    lsSet("_blocks",   newBlocks);
    lsSet("_mvblocks", newMvBlocks);
    if (!SUPA_OK) return;
    clearTimeout(syncTimer.current);
    setSyncStatus("saving");
    syncTimer.current = setTimeout(async () => {
      const [ok1, ok2, ok3] = await Promise.all([
        supaSet("rik_kv", "state",    newState),
        supaSet("rik_kv", "blocks",   newBlocks),
        supaSet("rik_kv", "mvblocks", newMvBlocks),
      ]);
      setSyncStatus(ok1 && ok2 && ok3 ? "synced" : "offline");
    }, 500);
  }, []);
  // Keep syncState alias for backward compat
  const syncState = (ns, nb) => syncAll(ns, nb, mvBlocks);

  const updateAppState = useCallback((newState) => {
    setAppState(newState);
    syncState(newState, blocks);
  }, [blocks, syncState]);

  const updateBlocks = useCallback((newBlocks) => {
    setBlocks(newBlocks);
    syncAll(appState, newBlocks, mvBlocks);
  }, [appState, mvBlocks, syncAll]);

  const updateMvBlocks = useCallback((newMvBlocks) => {
    setMvBlocks(newMvBlocks);
    syncAll(appState, blocks, newMvBlocks);
  }, [appState, blocks, syncAll]);

  const getTranState = (bId, tNr) => appState[tranKey(bId, tNr)] || {};
  const setTranState = (bId, tNr, upd) => {
    const k = tranKey(bId, tNr);
    const next = { ...appState, [k]: { ...appState[k], ...upd } };
    updateAppState(next);
  };

  const goHome = () => { setView("plan"); setActiveBlock(null); setActiveTran(null); };

  const handleStartCoach    = (b, t) => { setActiveBlock(b); setActiveTran(t); setView("coach");    window.scrollTo(0,0); };
  const handleVisaAvslutad  = (b, t) => { setActiveBlock(b); setActiveTran(t); setView("visa");     window.scrollTo(0,0); };
  const handleRedigera      = (b, t) => { setActiveBlock(b); setActiveTran(t); setView("redigera"); window.scrollTo(0,0); };
  const handleAvsluta = () => {
    setTranState(activeBlock.id, activeTran.nr, { avslutad:true, avslutadDatum:new Date().toISOString() });
    goHome();
  };

  const handleSparaRedigering = (nyaDelar) => {
    const newBlocks = blocks.map(b =>
      b.id !== activeBlock.id ? b : {
        ...b, trän: b.trän.map(t => t.nr !== activeTran.nr ? t : { ...t, delar: nyaDelar })
      }
    );
    updateBlocks(newBlocks);
    setView("plan");
  };

  // Sync-statusindikator
  const SyncBadge = () => {
    if (!SUPA_OK) return (
      <span className="flex items-center gap-1 text-[10px] text-slate-400 font-semibold">
        <WifiOff className="h-3 w-3"/>Lokal
      </span>
    );
    return (
      <span className={`flex items-center gap-1 text-[10px] font-semibold ${syncStatus==="synced"?"text-green-400":syncStatus==="saving"||syncStatus==="loading"?"text-yellow-400":"text-red-400"}`}>
        {syncStatus==="saving"||syncStatus==="loading" ? <Loader2 className="h-3 w-3 animate-spin"/> : syncStatus==="synced" ? <Wifi className="h-3 w-3"/> : <WifiOff className="h-3 w-3"/>}
        {syncStatus==="synced"?"Synkad":syncStatus==="saving"?"Sparar…":syncStatus==="loading"?"Laddar…":"Offline"}
      </span>
    );
  };

  const resolvedBlock = activeBlock ? blocks.find(b=>b.id===activeBlock.id)||activeBlock : null;
  const resolvedTran  = (resolvedBlock && activeTran) ? (resolvedBlock.trän.find(t=>t.nr===activeTran.nr)||activeTran) : activeTran;

  if (view==="ovningar") return (
    <OvningsbankVy favs={favs} setFavs={f=>{setFavs(f);saveF(f);}} onBack={goHome} onVälj={null} väljLabel={null}/>
  );
  if (view==="varderingar") return (
    <VarderingarVy onBack={goHome}/>
  );
  if (view==="arbetssatt") return (
    <ArbetssattVy onBack={goHome}/>
  );
  if (view==="redigera"&&resolvedBlock&&resolvedTran) return (
    <RedigeraVy block={resolvedBlock} tran={resolvedTran} onSpara={handleSparaRedigering} onBack={goHome}/>
  );
  if ((view==="coach"||view==="visa")&&resolvedBlock&&resolvedTran) return (
    <CoachMode
      tran={resolvedTran} block={resolvedBlock}
      tranState={getTranState(resolvedBlock.id, resolvedTran.nr)}
      onUpdateState={upd=>setTranState(resolvedBlock.id, resolvedTran.nr, upd)}
      onAvsluta={handleAvsluta} onOmstart={()=>{}}
      readOnly={view==="visa"} onHome={goHome}
      favs={favs}
      onFavToggle={f=>{setFavs(f);saveF(f);}}
    />
  );
  const handleRefreshTrupp = () => {
    // Fetches fresh player list — in production this would call laget.se API
    // For now: show a prompt to paste updated data, or reset to default TRUPP
    if (window.confirm("Återställ spelarlistan till standardlistan från laget.se?\nDetta ersätter eventuella lokala ändringar.")) {
      setTrupp(TRUPP);
      lsSet("_trupp", TRUPP);
      alert("Spelarlistan uppdaterad! Tips: för live-synk med laget.se, exportera truppen som JSON och klistra in i inställningarna.");
    }
  };

  return (
    <PlaneringsVy
      blocks={blocks} appState={appState}
      setAppState={updateAppState} setBlocks={updateBlocks}
      onStartCoach={handleStartCoach} onVisaAvslutad={handleVisaAvslutad}
      onRedigera={handleRedigera} onOvningsbank={()=>setView("ovningar")}
      onVarderingar={()=>setView("varderingar")}
      onArbetssatt={()=>setView("arbetssatt")}
      syncBadge={<SyncBadge/>}
      mvBlocks={mvBlocks}
      setMvBlocks={updateMvBlocks}
      trupp={trupp}
      onRefreshTrupp={handleRefreshTrupp}
    />
  );
}
